def solve(*args):
    if not args:
        return []

    purchase_history = []

    for order in args:
        order_details = {
            'order_number': order.get('order_number', None),
            'order_date': order.get('order_date', None)
        }
        purchase_history.append(order_details)

    return purchase_history
